using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 42);

// Load data
var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "customers.csv");
var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

// Build pipeline: map label, encode Region, concatenate features, train
var pipeline = mlContext.Transforms.CustomMapping<CustomerData, MappedLabel>(
        (input, output) => output.Label = input.Churned == "Yes",
        contractName: "ChurnMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        nameof(CustomerData.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

var model = pipeline.Fit(dataView);
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory,
        Churned = ""
    };

    var result = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        willChurn = result.PredictedLabel,
        confidence = result.Probability
    });
});

app.Run();

// --- Models ---

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

public class MappedLabel
{
    public bool Label { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

public record PredictRequest(float Age, float Income, string Region, float PurchaseHistory);

